test_assertions:
call_count = [0]
@retry(max_attempts=3, delay=0.0)
def flaky():
    call_count[0] += 1
    if call_count[0] < 3:
        raise ValueError('fail')
    return 'ok'
assert flaky() == 'ok'
assert call_count[0] == 3

import pytest
call_count = [0]
@retry(max_attempts=2, delay=0.0)
def always_fails():
    call_count[0] += 1
    raise ValueError('fail')
try:
    always_fails()
    assert False, 'should have raised'
except ValueError:
    pass
assert call_count[0] == 2
